import React, { useEffect, useMemo, useState } from 'react';
import {
    createCustomer,
    CreateCustomerInput,
    Customer,
    CustomerStatus,
    fetchCustomerById,
    fetchCustomers,
    PaymentStatus,
    updateCustomer,
    UpdateCustomerInput,
} from '../api/customers';

type FormMode = 'create' | 'edit';

interface CustomerFormState {
    name: string;
    email: string;
    phone: string;
    address: string;
    neighborhood: string;
    city: string;
    plan: string;
    status: CustomerStatus;
    monthlyFee: string;
    balanceDue: string;
    lastPaymentDate: string;
    paymentStatus: PaymentStatus;
    olt: string;
    ponPort: string;
    onuSerial: string;
    onuModel: string;
    rxPowerDbm: string;
    txPowerDbm: string;
    ipv4: string;
}

const emptyForm: CustomerFormState = {
    name: '',
    email: '',
    phone: '',
    address: '',
    neighborhood: '',
    city: '',
    plan: '',
    status: 'Ativo',
    monthlyFee: '0',
    balanceDue: '0',
    lastPaymentDate: new Date().toISOString().slice(0, 10),
    paymentStatus: 'Em dia',
    olt: '',
    ponPort: '',
    onuSerial: '',
    onuModel: '',
    rxPowerDbm: '-20',
    txPowerDbm: '2',
    ipv4: '',
};

const toCustomerForm = (customer: Customer): CustomerFormState => {
    return {
        name: customer.name,
        email: customer.email,
        phone: customer.phone,
        address: customer.address,
        neighborhood: customer.neighborhood,
        city: customer.city,
        plan: customer.plan,
        status: customer.status,
        monthlyFee: String(customer.financial.monthlyFee),
        balanceDue: String(customer.financial.balanceDue),
        lastPaymentDate: customer.financial.lastPaymentDate,
        paymentStatus: customer.financial.paymentStatus,
        olt: customer.connection.olt,
        ponPort: customer.connection.ponPort,
        onuSerial: customer.connection.onuSerial,
        onuModel: customer.connection.onuModel,
        rxPowerDbm: String(customer.connection.rxPowerDbm),
        txPowerDbm: String(customer.connection.txPowerDbm),
        ipv4: customer.connection.ipv4,
    };
};

const parseNumberSafe = (value: string): number => {
    const parsed = Number(value.replace(',', '.'));
    return Number.isFinite(parsed) ? parsed : 0;
};

const toCreatePayload = (form: CustomerFormState): CreateCustomerInput => {
    return {
        name: form.name,
        email: form.email,
        phone: form.phone,
        address: form.address,
        neighborhood: form.neighborhood,
        city: form.city,
        plan: form.plan,
        status: form.status,
        financial: {
            monthlyFee: parseNumberSafe(form.monthlyFee),
            balanceDue: parseNumberSafe(form.balanceDue),
            lastPaymentDate: form.lastPaymentDate,
            paymentStatus: form.paymentStatus,
        },
        connection: {
            olt: form.olt,
            ponPort: form.ponPort,
            onuSerial: form.onuSerial,
            onuModel: form.onuModel,
            rxPowerDbm: parseNumberSafe(form.rxPowerDbm),
            txPowerDbm: parseNumberSafe(form.txPowerDbm),
            ipv4: form.ipv4,
        },
    };
};

const toUpdatePayload = (form: CustomerFormState): UpdateCustomerInput => {
    return toCreatePayload(form);
};

const Customers: React.FC = () => {
    const [customers, setCustomers] = useState<Customer[]>([]);
    const [loading, setLoading] = useState<boolean>(true);
    const [error, setError] = useState<string | null>(null);
    const [successMessage, setSuccessMessage] = useState<string | null>(null);

    const [search, setSearch] = useState<string>('');
    const [currentPage, setCurrentPage] = useState<number>(1);

    const [selectedCustomer, setSelectedCustomer] = useState<Customer | null>(null);
    const [detailsLoading, setDetailsLoading] = useState<boolean>(false);
    const [formMode, setFormMode] = useState<FormMode>('create');
    const [formData, setFormData] = useState<CustomerFormState>(emptyForm);
    const [saving, setSaving] = useState<boolean>(false);

    const pageSize = 4;

    useEffect(() => {
        const load = async () => {
            try {
                const list = await fetchCustomers();
                setCustomers(list);
            } catch (err) {
                setError('Falha ao carregar clientes.');
            } finally {
                setLoading(false);
            }
        };

        load();
    }, []);

    useEffect(() => {
        if (!successMessage) return;

        const timer = window.setTimeout(() => {
            setSuccessMessage(null);
        }, 2500);

        return () => window.clearTimeout(timer);
    }, [successMessage]);

    const filteredCustomers = useMemo(() => {
        const term = search.trim().toLowerCase();
        if (!term) return customers;

        return customers.filter(
            (customer) =>
                customer.name.toLowerCase().includes(term)
                || customer.email.toLowerCase().includes(term)
                || customer.plan.toLowerCase().includes(term)
                || customer.phone.toLowerCase().includes(term)
                || customer.connection.onuSerial.toLowerCase().includes(term),
        );
    }, [customers, search]);

    const totalPages = Math.max(1, Math.ceil(filteredCustomers.length / pageSize));
    const safePage = Math.min(currentPage, totalPages);
    const start = (safePage - 1) * pageSize;
    const paginatedCustomers = filteredCustomers.slice(start, start + pageSize);

    const handlePrev = () => setCurrentPage((prev) => Math.max(1, prev - 1));
    const handleNext = () => setCurrentPage((prev) => Math.min(totalPages, prev + 1));

    const openCreateForm = () => {
        setError(null);
        setFormMode('create');
        setSelectedCustomer(null);
        setFormData(emptyForm);
    };

    const openEditForm = async (id: string) => {
        setError(null);
        setDetailsLoading(true);
        try {
            const customer = await fetchCustomerById(id);
            if (!customer) {
                setError('Cliente não encontrado para edição.');
                return;
            }

            setFormMode('edit');
            setSelectedCustomer(customer);
            setFormData(toCustomerForm(customer));
        } catch (err) {
            setError('Falha ao carregar cliente para edição.');
        } finally {
            setDetailsLoading(false);
        }
    };

    const openViewDetails = async (id: string) => {
        setError(null);
        setDetailsLoading(true);
        try {
            const customer = await fetchCustomerById(id);
            if (!customer) {
                setError('Cliente não encontrado para visualização.');
                return;
            }

            setSelectedCustomer(customer);
            setFormMode('create');
        } catch (err) {
            setError('Falha ao carregar detalhes do cliente.');
        } finally {
            setDetailsLoading(false);
        }
    };

    const handleFormChange = (field: keyof CustomerFormState, value: string) => {
        setFormData((prev) => ({ ...prev, [field]: value }));
    };

    const reloadCustomers = async () => {
        const list = await fetchCustomers();
        setCustomers(list);
    };

    const handleSubmit = async (event: React.FormEvent<HTMLFormElement>) => {
        event.preventDefault();
        setError(null);

        if (!formData.name.trim() || !formData.email.trim() || !formData.phone.trim() || !formData.plan.trim()) {
            setError('Preencha nome, email, telefone e plano para salvar o cliente.');
            return;
        }

        if (!formData.onuSerial.trim() || !formData.olt.trim() || !formData.ponPort.trim()) {
            setError('Preencha os dados técnicos de ONU, OLT e PON para salvar o cliente.');
            return;
        }

        setSaving(true);
        try {
            if (formMode === 'create') {
                const payload = toCreatePayload(formData);

                const created = await createCustomer(payload);
                setSelectedCustomer(created);
                setSuccessMessage('Cliente adicionado com sucesso.');
            } else if (selectedCustomer) {
                const payload = toUpdatePayload(formData);

                const updated = await updateCustomer(selectedCustomer.id, payload);
                if (!updated) {
                    setError('Não foi possível atualizar este cliente.');
                    return;
                }

                setSelectedCustomer(updated);
                setSuccessMessage('Cliente atualizado com sucesso.');
            }

            await reloadCustomers();
        } catch (err) {
            setError('Falha ao salvar cliente.');
        } finally {
            setSaving(false);
        }
    };

    return (
        <div style={{ padding: '1rem 1.25rem' }}>
            <h1>Clientes</h1>
            <p style={{ color: '#475569' }}>Listagem completa com adição, edição e visualização rápida financeira + conexão/ONU.</p>
            {loading && <p>Carregando clientes...</p>}
            {error && <p style={{ color: '#b91c1c' }}>{error}</p>}
            {successMessage && <p style={{ color: '#0f766e' }}>{successMessage}</p>}

            <div style={{ marginBottom: '0.8rem', display: 'flex', gap: '0.5rem', flexWrap: 'wrap' }}>
                <button onClick={openCreateForm}>+ Novo cliente</button>
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '1rem', alignItems: 'start' }}>
                <section>
                    <div style={{ marginBottom: '0.8rem' }}>
                        <input
                            type="text"
                            placeholder="Buscar por nome, email ou plano..."
                            value={search}
                            onChange={(e) => {
                                setSearch(e.target.value);
                                setCurrentPage(1);
                            }}
                            style={{ width: '100%', maxWidth: 420, padding: '0.5rem 0.65rem', border: '1px solid #cbd5e1', borderRadius: 8 }}
                        />
                    </div>

                    <table style={{ width: '100%', borderCollapse: 'collapse', background: '#fff', border: '1px solid #e2e8f0' }}>
                        <thead>
                            <tr style={{ background: '#f1f5f9' }}>
                                <th>ID</th>
                                <th>Nome</th>
                                <th>Email</th>
                                <th>Plano</th>
                                <th>Status</th>
                                <th>Financeiro</th>
                                <th>ONU/Rx</th>
                                <th>Ações</th>
                            </tr>
                        </thead>
                        <tbody>
                            {!loading && paginatedCustomers.map((customer) => (
                                <tr key={customer.id}>
                                    <td style={{ padding: '0.5rem', borderTop: '1px solid #e2e8f0' }}>{customer.id}</td>
                                    <td style={{ padding: '0.5rem', borderTop: '1px solid #e2e8f0' }}>{customer.name}</td>
                                    <td style={{ padding: '0.5rem', borderTop: '1px solid #e2e8f0' }}>{customer.email}</td>
                                    <td style={{ padding: '0.5rem', borderTop: '1px solid #e2e8f0' }}>{customer.plan}</td>
                                    <td style={{ padding: '0.5rem', borderTop: '1px solid #e2e8f0' }}>{customer.status}</td>
                                    <td style={{ padding: '0.5rem', borderTop: '1px solid #e2e8f0' }}>
                                        {customer.financial.paymentStatus} • R$ {customer.financial.balanceDue.toFixed(2)}
                                    </td>
                                    <td style={{ padding: '0.5rem', borderTop: '1px solid #e2e8f0' }}>
                                        {customer.connection.onuSerial} • {customer.connection.rxPowerDbm.toFixed(1)} dBm
                                    </td>
                                    <td style={{ padding: '0.5rem', borderTop: '1px solid #e2e8f0' }}>
                                        <div style={{ display: 'flex', gap: '0.4rem', flexWrap: 'wrap' }}>
                                            <button onClick={() => openViewDetails(customer.id)}>Ver</button>
                                            <button onClick={() => openEditForm(customer.id)}>Editar</button>
                                        </div>
                                    </td>
                                </tr>
                            ))}
                            {paginatedCustomers.length === 0 && (
                                <tr>
                                    <td style={{ padding: '0.75rem', textAlign: 'center', borderTop: '1px solid #e2e8f0' }} colSpan={8}>
                                        Nenhum cliente encontrado.
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>

                    <div style={{ marginTop: '0.8rem', display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                        <button onClick={handlePrev} disabled={safePage === 1}>Anterior</button>
                        <span>Página {safePage} de {totalPages}</span>
                        <button onClick={handleNext} disabled={safePage === totalPages}>Próxima</button>
                        <small style={{ color: '#64748b' }}>
                            {filteredCustomers.length} cliente(s) filtrado(s)
                        </small>
                    </div>
                </section>

                <aside style={{ background: '#fff', border: '1px solid #e2e8f0', borderRadius: 10, padding: '0.9rem' }}>
                    <h3 style={{ marginTop: 0 }}>
                        {formMode === 'create' ? 'Adicionar cliente' : 'Editar cliente'}
                    </h3>

                    <form onSubmit={handleSubmit} style={{ display: 'grid', gap: '0.6rem' }}>
                        <h4 style={{ margin: '0.2rem 0 0' }}>Dados cadastrais</h4>
                        <label>
                            <div>Nome</div>
                            <input value={formData.name} onChange={(e) => handleFormChange('name', e.target.value)} />
                        </label>

                        <label>
                            <div>Email</div>
                            <input type="email" value={formData.email} onChange={(e) => handleFormChange('email', e.target.value)} />
                        </label>

                        <label>
                            <div>Telefone</div>
                            <input value={formData.phone} onChange={(e) => handleFormChange('phone', e.target.value)} />
                        </label>

                        <label>
                            <div>Endereço</div>
                            <input value={formData.address} onChange={(e) => handleFormChange('address', e.target.value)} />
                        </label>

                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.5rem' }}>
                            <label>
                                <div>Bairro</div>
                                <input value={formData.neighborhood} onChange={(e) => handleFormChange('neighborhood', e.target.value)} />
                            </label>
                            <label>
                                <div>Cidade</div>
                                <input value={formData.city} onChange={(e) => handleFormChange('city', e.target.value)} />
                            </label>
                        </div>

                        <label>
                            <div>Plano</div>
                            <input value={formData.plan} onChange={(e) => handleFormChange('plan', e.target.value)} />
                        </label>

                        <label>
                            <div>Status</div>
                            <select value={formData.status} onChange={(e) => handleFormChange('status', e.target.value)}>
                                <option value="Ativo">Ativo</option>
                                <option value="Suspenso">Suspenso</option>
                            </select>
                        </label>

                        <h4 style={{ margin: '0.35rem 0 0' }}>Financeiro</h4>
                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.5rem' }}>
                            <label>
                                <div>Mensalidade (R$)</div>
                                <input value={formData.monthlyFee} onChange={(e) => handleFormChange('monthlyFee', e.target.value)} />
                            </label>
                            <label>
                                <div>Saldo em aberto (R$)</div>
                                <input value={formData.balanceDue} onChange={(e) => handleFormChange('balanceDue', e.target.value)} />
                            </label>
                        </div>

                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.5rem' }}>
                            <label>
                                <div>Último pagamento</div>
                                <input type="date" value={formData.lastPaymentDate} onChange={(e) => handleFormChange('lastPaymentDate', e.target.value)} />
                            </label>
                            <label>
                                <div>Status financeiro</div>
                                <select value={formData.paymentStatus} onChange={(e) => handleFormChange('paymentStatus', e.target.value)}>
                                    <option value="Em dia">Em dia</option>
                                    <option value="Atrasado">Atrasado</option>
                                </select>
                            </label>
                        </div>

                        <h4 style={{ margin: '0.35rem 0 0' }}>Conexão e ONU</h4>
                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.5rem' }}>
                            <label>
                                <div>OLT</div>
                                <input value={formData.olt} onChange={(e) => handleFormChange('olt', e.target.value)} />
                            </label>
                            <label>
                                <div>PON/Porta</div>
                                <input value={formData.ponPort} onChange={(e) => handleFormChange('ponPort', e.target.value)} />
                            </label>
                        </div>

                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.5rem' }}>
                            <label>
                                <div>Serial ONU</div>
                                <input value={formData.onuSerial} onChange={(e) => handleFormChange('onuSerial', e.target.value)} />
                            </label>
                            <label>
                                <div>Modelo ONU</div>
                                <input value={formData.onuModel} onChange={(e) => handleFormChange('onuModel', e.target.value)} />
                            </label>
                        </div>

                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.5rem' }}>
                            <label>
                                <div>Potência Rx (dBm)</div>
                                <input value={formData.rxPowerDbm} onChange={(e) => handleFormChange('rxPowerDbm', e.target.value)} />
                            </label>
                            <label>
                                <div>Potência Tx (dBm)</div>
                                <input value={formData.txPowerDbm} onChange={(e) => handleFormChange('txPowerDbm', e.target.value)} />
                            </label>
                        </div>

                        <label>
                            <div>IPv4</div>
                            <input value={formData.ipv4} onChange={(e) => handleFormChange('ipv4', e.target.value)} />
                        </label>

                        <div style={{ display: 'flex', gap: '0.5rem', flexWrap: 'wrap' }}>
                            <button type="submit" disabled={saving}>
                                {saving ? 'Salvando...' : formMode === 'create' ? 'Adicionar' : 'Salvar edição'}
                            </button>
                            <button type="button" onClick={openCreateForm}>Limpar</button>
                        </div>
                    </form>

                    <hr style={{ margin: '0.9rem 0' }} />

                    <h4 style={{ marginTop: 0 }}>Visualização</h4>
                    {detailsLoading && <p>Carregando detalhes...</p>}
                    {!detailsLoading && !selectedCustomer && (
                        <p style={{ color: '#64748b' }}>Selecione um cliente em “Ver” ou “Editar”.</p>
                    )}
                    {!detailsLoading && selectedCustomer && (
                        <div style={{ display: 'grid', gap: '0.55rem' }}>
                            <div style={{ display: 'grid', gap: '0.3rem' }}>
                                <div><strong>ID:</strong> {selectedCustomer.id}</div>
                                <div><strong>Nome:</strong> {selectedCustomer.name}</div>
                                <div><strong>Email:</strong> {selectedCustomer.email}</div>
                                <div><strong>Telefone:</strong> {selectedCustomer.phone}</div>
                                <div><strong>Plano:</strong> {selectedCustomer.plan}</div>
                            </div>

                            <section style={{ borderTop: '1px solid #e2e8f0', paddingTop: '0.5rem' }}>
                                <h5 style={{ margin: '0 0 0.35rem' }}>Financeiro</h5>
                                <div><strong>Mensalidade:</strong> R$ {selectedCustomer.financial.monthlyFee.toFixed(2)}</div>
                                <div><strong>Saldo em aberto:</strong> R$ {selectedCustomer.financial.balanceDue.toFixed(2)}</div>
                                <div><strong>Último pagamento:</strong> {selectedCustomer.financial.lastPaymentDate}</div>
                                <div><strong>Status:</strong> {selectedCustomer.financial.paymentStatus}</div>
                            </section>

                            <section style={{ borderTop: '1px solid #e2e8f0', paddingTop: '0.5rem' }}>
                                <h5 style={{ margin: '0 0 0.35rem' }}>Conexão / ONU</h5>
                                <div><strong>OLT/PON:</strong> {selectedCustomer.connection.olt} • {selectedCustomer.connection.ponPort}</div>
                                <div><strong>ONU:</strong> {selectedCustomer.connection.onuSerial} ({selectedCustomer.connection.onuModel})</div>
                                <div><strong>Potência Rx:</strong> {selectedCustomer.connection.rxPowerDbm.toFixed(1)} dBm</div>
                                <div><strong>Potência Tx:</strong> {selectedCustomer.connection.txPowerDbm.toFixed(1)} dBm</div>
                                <div><strong>IPv4:</strong> {selectedCustomer.connection.ipv4}</div>
                            </section>
                        </div>
                    )}
                </aside>
            </div>
        </div>
    );
};

export default Customers;
